"""
Set up the 'nuke' module

This initializes Nuke's internal modules and brings the symbols into this namespace
"""

import _nuke
from nuke_internal import *

# Bring in sub-modules from 'nuke_internal'. For imports to work as expected,
# e.g. 'import nuke.localization', we need to insert them into the sys.modules
# table as well as this module's symbol table
import importlib
import sys
__submods = [('geo', 'nuke_internal.geo'),
            ('localization', 'nuke_internal.localization'),
            ('memory2', 'nuke_internal.memory2'),
            ('rotopaint', 'nuke_internal.rotopaint'),
            ('splinewarp', 'nuke_internal.splinewarp'),
            ('curvelib', '_curvelib'),
            ('curveknob', '_curveknob'),
            ('nukemath', '_nukemath')]
for nukeName, importName in __submods:
  mod = importlib.import_module(importName)
  globals()[nukeName] = mod
  sys.modules['nuke.'+ nukeName] = mod

if _nuke.env['ExternalPython']:
  import _nuke_internal
  _nuke_internal.initExternalPython()
